import { createWorkflow, createAgent, Tool } from 'mastra';
import { z } from 'zod';

const searchTool = new Tool({
  name: 'web_search',
  description: 'Search web for research information',
  schema: z.object({
    query: z.string().describe('Search query'),
    num_results: z.number().default(10)
  }),
  execute: async ({ query }) => {
    // Serper/Tavily API call
    return { results: [], sources: [] };
  }
});

const researchAgent = createAgent({
  name: 'researcher',
  instructions: 'Conduct thorough research and cite sources',
  tools: [searchTool]
});

export const researchWorkflow = createWorkflow({
  name: 'research_pipeline',
  steps: [
    { agent: researchAgent, name: 'search_and_analyze' },
    { agent: researchAgent, name: 'synthesize_summary' }
  ]
});

import { Middleware } from 'mastra';

const sourceValidator: Middleware = async (context, next) => {
  const { toolResults } = context;

  // Validate source credibility
  const validSources = toolResults.filter(result => 
    isCredibleSource(result.url) && 
    isRecent(result.publishedDate)
  );

  context.validatedSources = validSources;
  await next();
};

function isCredibleSource(url: string): boolean {
  const credibleDomains = ['nytimes.com', 'bbc.com', 'reuters.com'];
  return credibleDomains.some(domain => url.includes(domain));
}

export default sourceValidator;

import { createAgent } from 'mastra';
import { z } from 'zod';

export const claimExtractor = createAgent({
  name: 'claim_extractor',
  instructions: `Extract all factual claims from sources. For each claim:
  1. Identify supporting evidence
  2. Rate confidence (high/medium/low)
  3. Flag potential bias
  4. Verify against multiple sources`,
  outputSchema: z.object({
    claims: z.array(z.object({
      text: z.string(),
      confidence: z.enum(['high', 'medium', 'low']),
      evidence: z.array(z.string()),
      sources: z.array(z.string()),
      biasRisk: z.string().optional()
    }))
  })
});

import { createAgent } from 'mastra';
import { PineconeStore } from '@langchain/pinecone';

const researchMemory = new PineconeStore({
  pineconeIndex: pinecone.Index('research-memory'),
  namespace: 'web_research'
});

export const persistentResearcher = createAgent({
  name: 'persistent_researcher',
  instructions: 'Use memory for research continuity but prioritize fresh sources',
  memory: researchMemory,
  tools: [searchTool, memoryRetrievalTool]
});

const memoryRetrievalTool = new Tool({
  name: 'retrieve_research_memory',
  schema: z.object({ topic: z.string() }),
  execute: async ({ topic }) => {
    const relevantResearch = await researchMemory.similaritySearch(topic, 5);
    return {
      past_findings: relevantResearch,
      retrieval_date: new Date().toISOString()
    };
  }
});

