import { Vex } from '@vex_dev/sdk';
import { Workflow } from 'mastra';

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY!,
  projectId: 'research-agents'
});

export const withVexGuardrails = (workflow: Workflow) => {
  return workflow.withMiddleware(async (context, next) => {
    // Validate inputs
    const inputCheck = await vex.verify({
      data: context.input,
      checks: ['source_verification', 'recency_check']
    });

    if (!inputCheck.valid) {
      throw new Error(`Validation failed: ${inputCheck.errors}`);
    }

    const result = await next();

    // Validate outputs
    const outputCheck = await vex.verify({
      data: result,
      checks: ['claim_accuracy', 'bias_detection']
    });

    return { ...result, vexReport: outputCheck };
  });
};

import { Vex } from '@vex_dev/sdk';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY! });

export const verifySources = async (searchResults: any[]) => {
  const verified = await Promise.all(
    searchResults.map(async (result) => {
      const report = await vex.verify({
        data: {
          url: result.url,
          title: result.title,
          published: result.publishedDate,
          content: result.snippet
        },
        checks: [
          {
            type: 'source_verification',
            config: { min_credibility_score: 0.7 }
          },
          {
            type: 'recency_check',
            config: { max_age_days: 30 }
          }
        ]
      });

      return { ...result, vex_verified: report.valid, score: report.score };
    })
  );

  return verified.filter(r => r.vex_verified);
};

import { Vex } from '@vex_dev/sdk';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY! });

export const verifyClaims = async (claims: any[]) => {
  const verifiedClaims = await Promise.all(
    claims.map(async (claim) => {
      const report = await vex.verify({
        data: {
          claim: claim.text,
          evidence: claim.evidence,
          sources: claim.sources,
          context: claim.context
        },
        checks: [
          {
            type: 'claim_accuracy',
            config: { require_corroboration: 2 }
          },
          {
            type: 'bias_detection',
            config: { flag_polarization: true }
          },
          {
            type: 'factual_consistency',
            config: { cross_verify_sources: true }
          }
        ]
      });

      return {
        ...claim,
        verified: report.valid,
        confidence_adjusted: report.score,
        issues: report.issues || []
      };
    })
  );

  return verifiedClaims;
};
